--
-- Estructura para la vista `vista_resumen_departamento`
--
DROP TABLE IF EXISTS `vista_resumen_departamento`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_resumen_departamento`  AS SELECT `d`.`id` AS `departamento_id`, `d`.`nombre` AS `departamento`, count(distinct `dv`.`id`) AS `total_registros`, sum(`dv`.`programado`) AS `total_programado`, sum(`dv`.`ejecutado`) AS `total_ejecutado`, round((case when (sum(`dv`.`programado`) > 0) then ((sum(`dv`.`ejecutado`) / sum(`dv`.`programado`)) * 100) else 0 end),2) AS `porcentaje_ejecucion`, sum(`dv`.`hombres`) AS `total_hombres`, sum(`dv`.`mujeres`) AS `total_mujeres`, sum(`dv`.`total_personas`) AS `total_beneficiarios`, sum(`dv`.`vigente_financiera`) AS `total_financiero_vigente`, sum(`dv`.`financiera_ejecutado`) AS `total_financiero_ejecutado` FROM (`departamentos` `d` left join `datos_vider` `dv` on((`d`.`id` = `dv`.`departamento_id`))) GROUP BY `d`.`id`, `d`.`nombre` ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_resumen_dependencia`
--
DROP TABLE IF EXISTS `vista_resumen_dependencia`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_resumen_dependencia`  AS SELECT `dep`.`id` AS `dependencia_id`, `dep`.`nombre` AS `dependencia`, `dep`.`siglas` AS `siglas`, count(distinct `dv`.`id`) AS `total_registros`, sum(`dv`.`programado`) AS `total_programado`, sum(`dv`.`ejecutado`) AS `total_ejecutado`, sum(`dv`.`total_personas`) AS `total_beneficiarios`, sum(`dv`.`vigente_financiera`) AS `total_financiero_vigente`, sum(`dv`.`financiera_ejecutado`) AS `total_financiero_ejecutado` FROM (`dependencias` `dep` left join `datos_vider` `dv` on((`dep`.`id` = `dv`.`dependencia_id`))) GROUP BY `dep`.`id`, `dep`.`nombre`, `dep`.`siglas` ;

-- --------------------------------------------------------

--
-- Estructura para la vista `vista_resumen_municipio`
--
DROP TABLE IF EXISTS `vista_resumen_municipio`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `vista_resumen_municipio`  AS SELECT `m`.`id` AS `municipio_id`, `m`.`nombre` AS `municipio`, `d`.`id` AS `departamento_id`, `d`.`nombre` AS `departamento`, count(distinct `dv`.`id`) AS `total_registros`, sum(`dv`.`programado`) AS `total_programado`, sum(`dv`.`ejecutado`) AS `total_ejecutado`, sum(`dv`.`total_personas`) AS `total_beneficiarios`, sum(`dv`.`vigente_financiera`) AS `total_financiero_vigente`, sum(`dv`.`financiera_ejecutado`) AS `total_financiero_ejecutado` FROM ((`municipios` `m` join `departamentos` `d` on((`m`.`departamento_id` = `d`.`id`))) left join `datos_vider` `dv` on((`m`.`id` = `dv`.`municipio_id`))) GROUP BY `m`.`id`, `m`.`nombre`, `d`.`id`, `d`.`nombre` ;

